import{_ as e,c as t,o as r,ae as o}from"./chunks/framework.Cd-3tpCq.js";const m=JSON.parse('{"title":"玩家行为准则","description":"","frontmatter":{},"headers":[],"relativePath":"examplex.md","filePath":"examplex.md"}'),l={name:"examplex.md"};function i(p,a,s,h,n,c){return r(),t("div",null,a[0]||(a[0]=[o('<h1 id="玩家行为准则" tabindex="-1">玩家行为准则 <a class="header-anchor" href="#玩家行为准则" aria-label="Permalink to &quot;玩家行为准则&quot;">​</a></h1><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">须知</p><p>欢迎来到幻境灵云服务器！为了确保所有玩家能够享受到愉快的游戏体验，我们制定了以下服务器服规，请务必遵守，违反规定将受到相应的处罚。</p></div><h2 id="一-一般事项" tabindex="-1">一. 一般事项 <a class="header-anchor" href="#一-一般事项" aria-label="Permalink to &quot;一. 一般事项&quot;">​</a></h2><p>尊重他人：请文明交流，不得使用攻击性言论、人身攻击或任何其他不当行为，以维护友好的游戏环境。</p><p>禁止使用非法程序：严禁使用任何形式的作弊、外挂、修改客户端或其他非法程序。任何形式的利用漏洞、BUG或不正当手段获取优势的行为都是严重违规的。</p><h2 id="二-禁止行为" tabindex="-1">二.禁止行为 <a class="header-anchor" href="#二-禁止行为" aria-label="Permalink to &quot;二.禁止行为&quot;">​</a></h2><p>恶意卡顿: 禁止恶意造成服务器卡顿，其他玩家客户端卡顿等等行为。</p><p>滥用BUG：禁止故意利用游戏中的漏洞或BUG，包括但不限于物品复制、传送漏洞等。原版特性除外。</p><p>作弊行为：禁止任何形式的作弊行为，包括但不限于修改游戏文件、使用第三方软件或脚本进行作弊等。</p><p>恶意破坏：禁止对其他玩家的建筑、领地及领地周边进行恶意破坏、破坏性行为或捣乱行为。</p><p>私下交易: 为避免市场环境遭到破坏，玩家被诈骗等等，禁止私下进行人民币交易。</p><h2 id="三-处罚措施" tabindex="-1">三.处罚措施 <a class="header-anchor" href="#三-处罚措施" aria-label="Permalink to &quot;三.处罚措施&quot;">​</a></h2><p>警告：对违反规定的玩家但获得被害人的谅解我们给予警告，并要求其立即停止违规行为。</p><p>永久封禁：对于恶意破坏、作弊行为严重的玩家，我们将采取永久封禁账号的措施，禁止其再次进入服务器。</p><h2 id="四-申诉" tabindex="-1">四.申诉 <a class="header-anchor" href="#四-申诉" aria-label="Permalink to &quot;四.申诉&quot;">​</a></h2><p>如果您觉得自己受到了不公平的对待，或者对处罚有异议，您可以通过我的官方群聊或联系我们的管理员进行申诉。我们将认真审核每一份申诉，并尽可能给予公正的处理。</p><h2 id="五-最终解释权" tabindex="-1">五.最终解释权 <a class="header-anchor" href="#五-最终解释权" aria-label="Permalink to &quot;五.最终解释权&quot;">​</a></h2><p>我们保留对服务器服规进行解释和调整的权利，并有权根据情况对违规行为进行处理。所有的处罚决定将以维护服务器秩序和游戏环境为目标。</p><p>玩家们拥有监督与举报的权力，我们管理团队坚决维护服务器内的规则。</p><h2 id="" tabindex="-1"><a class="header-anchor" href="#" aria-label="Permalink to &quot;&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">须知</p><p>我们对违规行为的态度，<a href="#">零容忍</a>,欢迎群友们积极举报违规行为。</p></div>',22)]))}const u=e(l,[["render",i]]);export{m as __pageData,u as default};
